{"version":3,"sources":["file:///D:/Works/Cocos/WxMiniGames/FlowersArrangement/assets/scripts/ScreenAdapter.ts"],"names":["_decorator","Component","view","Size","ccclass","property","ScreenAdapter","onLoad","adjustScreen","on","onDestroy","off","canvas","node","getComponent","screenSize","getVisibleSize","designRatio","designResolution","width","height","screenRatio","fitHeight","fitWidth"],"mappings":";;;;;;;;;;;;;;;;AAASA,MAAAA,U,OAAAA,U;AAAYC,MAAAA,S,OAAAA,S;AAAWC,MAAAA,I,OAAAA,I;AAAMC,MAAAA,I,OAAAA,I;;;;;;;;;OAChC;AAAEC,QAAAA,OAAF;AAAWC,QAAAA;AAAX,O,GAAwBL,U;;+BAGjBM,a,WADZF,OAAO,CAAC,eAAD,C,UAEHC,QAAQ,CAACF,IAAD,C,2BAFb,MACaG,aADb,SACmCL,SADnC,CAC6C;AAAA;AAAA;;AAAA;AAAA;;AAIzCM,QAAAA,MAAM,GAAG;AACL;AACA,eAAKC,YAAL,GAFK,CAGL;;AACAN,UAAAA,IAAI,CAACO,EAAL,CAAQ,QAAR,EAAkB,KAAKD,YAAvB,EAAqC,IAArC;AACH;;AAEDE,QAAAA,SAAS,GAAG;AACRR,UAAAA,IAAI,CAACS,GAAL,CAAS,QAAT,EAAmB,KAAKH,YAAxB,EAAsC,IAAtC;AACH;;AAEDA,QAAAA,YAAY,GAAG;AACX,gBAAMI,MAAM,GAAG,KAAKC,IAAL,CAAUC,YAAV,CAAuB,WAAvB,CAAf;AACA,cAAI,CAACF,MAAL,EAAa;AAEb,gBAAMG,UAAU,GAAGb,IAAI,CAACc,cAAL,EAAnB;AACA,gBAAMC,WAAW,GAAG,KAAKC,gBAAL,CAAsBC,KAAtB,GAA8B,KAAKD,gBAAL,CAAsBE,MAAxE;AACA,gBAAMC,WAAW,GAAGN,UAAU,CAACI,KAAX,GAAmBJ,UAAU,CAACK,MAAlD,CANW,CAQX;;AACA,cAAIC,WAAW,IAAIJ,WAAnB,EAAgC;AAC5B;AACAL,YAAAA,MAAM,CAACU,SAAP,GAAmB,IAAnB;AACAV,YAAAA,MAAM,CAACW,QAAP,GAAkB,KAAlB;AACH,WAJD,MAIO;AACH;AACAX,YAAAA,MAAM,CAACU,SAAP,GAAmB,KAAnB;AACAV,YAAAA,MAAM,CAACW,QAAP,GAAkB,IAAlB;AACH;AACJ;;AAjCwC,O;;;;;iBAEf,IAAIpB,IAAJ,CAAS,CAAT,EAAY,CAAZ,C","sourcesContent":["import { _decorator, Component, view, Size, screen, Widget } from 'cc';\r\nconst { ccclass, property } = _decorator;\r\n\r\n@ccclass('ScreenAdapter')\r\nexport class ScreenAdapter extends Component {\r\n    @property(Size)\r\n    public designResolution = new Size(0, 0);\r\n\r\n    onLoad() {\r\n        // ��ʼ����\r\n        this.adjustScreen();\r\n        // ������Ļ��С�仯������������ڵ������豸��ת��\r\n        view.on('resize', this.adjustScreen, this);\r\n    }\r\n\r\n    onDestroy() {\r\n        view.off('resize', this.adjustScreen, this);\r\n    }\r\n\r\n    adjustScreen() {\r\n        const canvas = this.node.getComponent('cc.Canvas');\r\n        if (!canvas) return;\r\n\r\n        const screenSize = view.getVisibleSize();\r\n        const designRatio = this.designResolution.width / this.designResolution.height;\r\n        const screenRatio = screenSize.width / screenSize.height;\r\n\r\n        // ��̬ѡ���������\r\n        if (screenRatio >= designRatio) {\r\n            // ��Ļ�����������ͬ -> �̶��߶ȣ�������ȿ��ܳ��ֵĺڱ�\r\n            canvas.fitHeight = true;\r\n            canvas.fitWidth = false;\r\n        } else {\r\n            // ��Ļ��խ -> �̶����ȣ�����߶ȿ��ܳ��ֵĺڱ�\r\n            canvas.fitHeight = false;\r\n            canvas.fitWidth = true;\r\n        }\r\n    }\r\n}"]}